// NODE: Session Manager
// Receives Telegram updates from the n8n Telegram Trigger node and tracks
// 2-message session state per chat.
// Message 1: Voice audio only
// Message 2: Caption + Subject (Photo/Video) + B-Roll Video(s) → triggers pipeline

const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

// The Telegram Trigger node exposes the update directly (not nested under .body)
const update = $input.first().json;
const message = update.message || update.edited_message || null;

if (!message) {
  return [{ json: { skip: true, reason: "no message" } }];
}

const chatId = String(message.chat.id);

// Load existing session from workflow static data
const staticData = $getWorkflowStaticData("global");
if (!staticData.sessions) staticData.sessions = {};

let session = staticData.sessions[chatId] || { step: 0 };

// Prevent duplicate processing if already in progress (but allow new voice notes)
if (session.step === 2 && !message.voice) {
  return [{ json: { skip: true, reason: "already processing" } }];
}

// ── STEP 1: Voice message ──────────────────────────────────────────────────
if (message.voice && (session.step === 0 || session.step === 2)) {
  const fileId = message.voice.file_id;

  // Resolve file path via Telegram API
  const fileInfoResp = await this.helpers.httpRequest({
    method: "GET",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${fileId}`,
  });

  const filePath = fileInfoResp.result.file_path;
  const audioUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${filePath}`;

  session = { step: 1, chatId, audioUrl, audioFileId: fileId, videos: [] };
  staticData.sessions[chatId] = session;

  // Acknowledge receipt
  await this.helpers.httpRequest({
    method: "POST",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: {
      chat_id: chatId,
      text: "🎙️ Got your voice note!\n\nNow send a single message (or an album) with:\n📝 Caption (as message text)\n👤 A video of you (or a photo)\n🎬 One or more clips (b-roll)",
    },
    json: true,
  });

  return [{ json: { skip: true, reason: "waiting for step 2" } }];
}

// ── STEP 2: Accumulate Caption + Subject + Videos ─────────────────────────
if (session.step === 1) {
  const currentCaption = message.caption || message.text || "";
  const photo = message.photo;
  const video = message.video;

  let updated = false;

  // 1. Accumulate Caption (if we don't have one yet)
  if (currentCaption && !session.caption) {
    session.caption = currentCaption;
    updated = true;
  }

  // 2. Accumulate Subject (The first person-centric media we get)
  // If we get multiple videos, the first one is the subject, others are b-roll
  if (!session.subjectUrl) {
    if (photo) {
      const bestPhoto = photo[photo.length - 1];
      const photoInfoResp = await this.helpers.httpRequest({
        method: "GET",
        url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${bestPhoto.file_id}`,
      });
      session.subjectUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${photoInfoResp.result.file_path}`;
      session.subjectType = "image";
      updated = true;
    } else if (video) {
      const videoInfoResp = await this.helpers.httpRequest({
        method: "GET",
        url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${video.file_id}`,
      });
      session.subjectUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${videoInfoResp.result.file_path}`;
      session.subjectType = "video";
      updated = true;
    }
  } else if (video) {
    // 3. Accumulate B-Roll Video
    const videoInfoResp = await this.helpers.httpRequest({
      method: "GET",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/getFile?file_id=${video.file_id}`,
    });
    const videoUrl = `https://api.telegram.org/file/bot${TELEGRAM_BOT_TOKEN}/${videoInfoResp.result.file_path}`;

    if (!session.videos) session.videos = [];
    if (!session.videos.find(v => v.fileId === video.file_id)) {
      session.videos.push({ fileId: video.file_id, url: videoUrl, duration: video.duration });
      updated = true;
    }
  }

  // Save updated session state
  staticData.sessions[chatId] = session;

  // 4. Check if we have everything needed to proceed
  const hasCaption = !!session.caption;
  const hasSubject = !!session.subjectUrl;
  const hasVideos = session.videos && session.videos.length > 0;

  if (hasCaption && hasSubject && hasVideos) {
    // TRIGGER PIPELINE
    session.step = 2; // Move to "processing" state
    staticData.sessions[chatId] = session;

    await this.helpers.httpRequest({
      method: "POST",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: "⚙️ All assets received! Starting video generation pipeline...\n\nThis may take a few minutes ☕",
      },
      json: true,
    });

    return [{
      json: {
        skip: false,
        chatId,
        audioUrl: session.audioUrl,
        subjectUrl: session.subjectUrl,
        subjectType: session.subjectType,
        videos: session.videos,
        rawCaption: session.caption,
      },
    }];
  }

  // 5. Still collecting
  if (updated && !message.media_group_id) {
    const missing = [];
    if (!hasCaption) missing.push("📝 caption");
    if (!hasSubject) missing.push("👤 you (video/photo)");
    if (!hasVideos) missing.push("🎬 clips (b-roll)");

    await this.helpers.httpRequest({
      method: "POST",
      url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
      body: {
        chat_id: chatId,
        text: `📥 Received some assets. Still missing: ${missing.join(", ")}.`,
      },
      json: true,
    });
  }

  return [{ json: { skip: true, reason: "collecting assets", hasCaption, hasSubject, videoCount: (session.videos || []).length } }];
}

// ── DEFAULT: Unexpected State Reset ───────────────────────────────────────
delete staticData.sessions[chatId];
await this.helpers.httpRequest({
  method: "POST",
  url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
  body: {
    chat_id: chatId,
    text: "👋 Send a voice note to start! The bot will guide you through the next steps.",
  },
  json: true,
});

return [{ json: { skip: true, reason: "unexpected state reset" } }];

// NODE: Transcribe Audio
// Sends the Telegram voice note URL to fal.ai Whisper for transcription
// Uses fal-ai/whisper which accepts a direct audio URL — no download needed

const FAL_AI_API_KEY = "b58c67f2-94ec-4cfa-bfb7-158a15203b29:54446e43821d9169aba9d11b0f50f536";

const { audioUrl, chatId, photoUrl, videos, rawCaption } = $input.first().json;

// Submit transcription job to fal.ai Whisper (supports Telegram .ogg files)
const submitResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://queue.fal.run/fal-ai/whisper",
  headers: {
    Authorization: `Key ${FAL_AI_API_KEY}`,
    "Content-Type": "application/json",
  },
  body: JSON.stringify({
    audio_url: audioUrl,
    task: "transcribe",
    language: "en",
    chunk_level: "segment",
    version: "3",
  }),
});

const requestId = submitResp.request_id;
if (!requestId) {
  throw new Error("fal.ai Whisper did not return a request_id: " + JSON.stringify(submitResp));
}

// Poll until complete (max 2 minutes)
let transcription = "";
for (let i = 0; i < 24; i++) {
  await new Promise((r) => setTimeout(r, 5000));

  const statusResp = await this.helpers.httpRequest({
    method: "GET",
    url: `https://queue.fal.run/fal-ai/whisper/requests/${requestId}/status`,
    headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
  });

  if (statusResp.status === "COMPLETED") {
    const resultResp = await this.helpers.httpRequest({
      method: "GET",
      url: `https://queue.fal.run/fal-ai/whisper/requests/${requestId}`,
      headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
    });
    // fal.ai Whisper returns: { text: "...", chunks: [...] }
    transcription = resultResp.text || resultResp.transcription || "";
    break;
  }

  if (statusResp.status === "FAILED") {
    throw new Error("fal.ai Whisper transcription failed: " + JSON.stringify(statusResp));
  }
}

if (!transcription) {
  throw new Error("Timeout waiting for Whisper transcription result");
}

return [{
  json: {
    chatId,
    audioUrl,
    photoUrl,
    videos,
    rawCaption,
    transcription,
  },
}];

// NODE: Generate A-Roll via fal.ai (Sync Lipsync 2 Pro)
// High-quality lip-sync for both images and videos.
// Sync Lipsync 2 Pro supports images as visual input directly (passed to video_url).

const FAL_AI_API_KEY = "b58c67f2-94ec-4cfa-bfb7-158a15203b29:54446e43821d9169aba9d11b0f50f536";

const { chatId, audioUrl, subjectUrl, videos, rawCaption, transcription } = $input.first().json;

// ── STEP 1: Submit Lip-sync Job ──────────────────────────────────────────
// We pass the subject (Photo or Video) directly to video_url
const submitResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://queue.fal.run/fal-ai/sync-lipsync/v2/pro",
  headers: {
    Authorization: `Key ${FAL_AI_API_KEY}`,
    "Content-Type": "application/json",
  },
  body: {
    video_url: subjectUrl,
    audio_url: audioUrl,
  },
});

const statusUrl = submitResp.status_url;
const responseUrl = submitResp.response_url;

if (!statusUrl) {
  throw new Error("fal.ai did not return required queue URLs: " + JSON.stringify(submitResp));
}

// ── STEP 2: Poll for completion ─────────────────────────────────────────
let aRollUrl = null;
for (let i = 0; i < 48; i++) { // Max 4 minutes (high quality takes longer)
  await new Promise((r) => setTimeout(r, 5000));

  const statusResp = await this.helpers.httpRequest({
    method: "GET",
    url: statusUrl,
    headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
  });

  if (statusResp.status === "COMPLETED") {
    const resultResp = await this.helpers.httpRequest({
      method: "GET",
      url: responseUrl,
      headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
    });

    // Check possible response paths
    aRollUrl = resultResp.video?.url || resultResp.output?.video_url || resultResp.video_url || resultResp.url;
    break;
  }

  if (statusResp.status === "FAILED") {
    throw new Error("Sync Lipsync 2 Pro job failed: " + JSON.stringify(statusResp));
  }
}

if (!aRollUrl) {
  throw new Error("Timeout waiting for Lip-sync result");
}

return [{
  json: {
    chatId,
    aRollUrl,
    videos,
    rawCaption,
    transcription,
  },
}];

// NODE: Analyze B-Roll & Create Edit Plan
// Uses OpenRouter (GPT-4o vision) to analyze each b-roll video thumbnail,
// then uses the transcription to plan when to insert each b-roll clip.

const OPENROUTER_API_KEY = "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";
const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

const { chatId, aRollUrl, videos, rawCaption, transcription } = $input.first().json;

// ── Step 1: Describe each b-roll video (via first frame / thumbnail) ──────
const videoDescriptions = [];
for (const vid of videos) {
  // Download first ~10KB of the video to use as context (or use URL directly)
  // We'll ask the model to infer from URL metadata + description request
  const descResp = await this.helpers.httpRequest({
    method: "POST",
    url: "https://openrouter.ai/api/v1/chat/completions",
    headers: {
      Authorization: `Bearer ${OPENROUTER_API_KEY}`,
      "Content-Type": "application/json",
      "HTTP-Referer": "https://n8n.workflow",
      "X-Title": "Video Editor Bot",
    },
    body: JSON.stringify({
      model: "openai/gpt-4o",
      messages: [
        {
          role: "user",
          content: [
            {
              type: "text",
              text: `You are analyzing a b-roll video clip for a social media video editor.
The video URL is: ${vid.url}
Duration: ${vid.duration || "unknown"} seconds

Based on the URL and any context you can infer, describe:
1. What this b-roll clip likely shows (visual content, mood, setting)
2. What topics or keywords it best matches
3. Ideal usage duration for a b-roll insert (2-5 seconds recommended)

Be concise. Return JSON only:
{"description": "...", "keywords": ["..."], "suggestedDuration": 3}`,
            },
          ],
        },
      ],
      max_tokens: 300,
    }),
  });

  let desc = { description: "b-roll clip", keywords: [], suggestedDuration: 3 };
  try {
    const raw = descResp.choices[0].message.content.replace(/```json|```/g, "").trim();
    desc = JSON.parse(raw);
  } catch (e) {
    desc.description = descResp.choices[0]?.message?.content || "b-roll clip";
  }

  videoDescriptions.push({ ...vid, ...desc });
}

// ── Step 2: Create edit plan using transcription ───────────────────────────
const brollSummary = videoDescriptions
  .map((v, i) => `Clip ${i + 1}: "${v.description}" | keywords: ${v.keywords.join(", ")} | suggested: ${v.suggestedDuration}s`)
  .join("\n");

const planResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://openrouter.ai/api/v1/chat/completions",
  headers: {
    Authorization: `Bearer ${OPENROUTER_API_KEY}`,
    "Content-Type": "application/json",
    "HTTP-Referer": "https://n8n.workflow",
    "X-Title": "Video Editor Bot",
  },
  body: JSON.stringify({
    model: "openai/gpt-4o",
    messages: [
      {
        role: "system",
        content: `You are a professional social media video editor. Your job is to plan b-roll inserts over an a-roll talking-head video.
Rules:
- First 3 seconds: always show the speaker (a-roll) for hook
- B-roll should match what the speaker is saying
- Each b-roll insert: 2-5 seconds
- Leave speaker visible during key emotional moments
- Return ONLY valid JSON`,
      },
      {
        role: "user",
        content: `TRANSCRIPTION (a-roll):
"${transcription}"

AVAILABLE B-ROLL CLIPS:
${brollSummary}

Create a b-roll edit plan. For each insert specify:
- startTime (seconds into the video)
- duration (seconds)
- clipIndex (0-based index from the list above)
- reason (why this clip fits here)

Return JSON array: [{"startTime": 5, "duration": 3, "clipIndex": 0, "reason": "..."}]`,
      },
    ],
    max_tokens: 800,
  }),
});

let editPlan = [];
try {
  const raw = planResp.choices[0].message.content.replace(/```json|```/g, "").trim();
  editPlan = JSON.parse(raw);
} catch (e) {
  // fallback: insert clips evenly
  const estimatedDuration = transcription.split(" ").length / 2.5; // rough: 2.5 words/sec
  editPlan = videoDescriptions.map((v, i) => ({
    startTime: 4 + i * 6,
    duration: v.suggestedDuration || 3,
    clipIndex: i,
    reason: "evenly distributed fallback",
  }));
}

return [{
  json: {
    chatId,
    aRollUrl,
    videos: videoDescriptions,
    rawCaption,
    transcription,
    editPlan,
  },
}];

// NODE: Compose Final Video
// Uses fal.ai ffmpeg-api (or video-merge) to composite b-roll over a-roll
// according to the edit plan.

const FAL_AI_API_KEY = "b58c67f2-94ec-4cfa-bfb7-158a15203b29:54446e43821d9169aba9d11b0f50f536";

const { chatId, aRollUrl, videos, rawCaption, transcription, editPlan } = $input.first().json;

// Build FFmpeg filter_complex command for overlaying b-roll at timestamps
// fal.ai exposes an ffmpeg endpoint: fal-ai/ffmpeg-api

// Construct inputs array: [0] = a-roll, [1..n] = b-roll clips
const inputs = [{ url: aRollUrl }];
for (const plan of editPlan) {
  const clip = videos[plan.clipIndex];
  if (clip) inputs.push({ url: clip.url });
}

// Build FFmpeg filter_complex for picture-in-picture / full replace
// We'll do full-frame b-roll overlay (replaces a-roll during b-roll windows)
let filterParts = [];
let currentInput = "[0:v]";
let currentAudio = "[0:a]";
let brollIdx = 1;

// Start with a-roll as base
filterParts.push(`[0:v]copy[base]`);
let prevOutput = "[base]";

for (const plan of editPlan) {
  const clip = videos[plan.clipIndex];
  if (!clip) continue;

  const inputIdx = brollIdx;
  brollIdx++;

  // Scale b-roll to match a-roll resolution
  filterParts.push(
    `[${inputIdx}:v]scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2,setsar=1[broll${inputIdx}]`
  );

  // Overlay b-roll over a-roll at timestamp window
  const outLabel = `out${inputIdx}`;
  filterParts.push(
    `${prevOutput}[broll${inputIdx}]overlay=0:0:enable='between(t,${plan.startTime},${plan.startTime + plan.duration})'[${outLabel}]`
  );

  prevOutput = `[${outLabel}]`;
}

const filterComplex = filterParts.join("; ");

// Submit to fal.ai ffmpeg endpoint
const submitResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://queue.fal.run/fal-ai/ffmpeg-api/compose",
  headers: {
    Authorization: `Key ${FAL_AI_API_KEY}`,
    "Content-Type": "application/json",
  },
  body: JSON.stringify({
    inputs: inputs,
    filter_complex: filterComplex,
    output_options: {
      format: "mp4",
      video_codec: "libx264",
      audio_codec: "aac",
      map_video: prevOutput,
      map_audio: "[0:a]",
    },
  }),
});

const requestId = submitResp.request_id;
if (!requestId) {
  // Fallback: return the a-roll as final video if composition fails
  console.log("FFmpeg compose failed, returning a-roll as final:", JSON.stringify(submitResp));
  return [{
    json: {
      chatId,
      finalVideoUrl: aRollUrl,
      rawCaption,
      transcription,
      editPlan,
      compositionNote: "B-roll composition unavailable; returning a-roll only",
    },
  }];
}

// Poll for completion
let finalVideoUrl = null;
for (let i = 0; i < 36; i++) {
  await new Promise((r) => setTimeout(r, 5000));

  const statusResp = await this.helpers.httpRequest({
    method: "GET",
    url: `https://queue.fal.run/fal-ai/ffmpeg-api/compose/requests/${requestId}/status`,
    headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
  });

  if (statusResp.status === "COMPLETED") {
    const resultResp = await this.helpers.httpRequest({
      method: "GET",
      url: `https://queue.fal.run/fal-ai/ffmpeg-api/compose/requests/${requestId}`,
      headers: { Authorization: `Key ${FAL_AI_API_KEY}` },
    });
    finalVideoUrl = resultResp.video?.url || resultResp.output_url || resultResp.url;
    break;
  }

  if (statusResp.status === "FAILED") {
    // Fallback to a-roll only
    finalVideoUrl = aRollUrl;
    break;
  }
}

if (!finalVideoUrl) finalVideoUrl = aRollUrl; // timeout fallback

return [{
  json: {
    chatId,
    finalVideoUrl,
    rawCaption,
    transcription,
    editPlan,
  },
}];

// NODE: Generate Caption & Send Final Video
// Enriches the raw caption with AI, adds viral hashtags,
// then sends the final composed video back to the user on Telegram.

const OPENROUTER_API_KEY = "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";
const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

const { chatId, finalVideoUrl, rawCaption, transcription, editPlan } = $input.first().json;

// ── Step 1: Generate enriched caption ─────────────────────────────────────
const captionResp = await this.helpers.httpRequest({
  method: "POST",
  url: "https://openrouter.ai/api/v1/chat/completions",
  headers: {
    Authorization: `Bearer ${OPENROUTER_API_KEY}`,
    "Content-Type": "application/json",
    "HTTP-Referer": "https://n8n.workflow",
    "X-Title": "Video Caption Generator",
  },
  body: JSON.stringify({
    model: "openai/gpt-4o",
    messages: [
      {
        role: "system",
        content: `You are a viral social media content strategist specializing in short-form video (TikTok, Instagram Reels, YouTube Shorts).
Your job: take a raw video caption idea + transcript and turn it into a hook-driven, engaging caption with viral hashtags.

Rules:
- Start with a strong hook (first line = stop-the-scroll)
- Keep it under 150 words
- Natural, conversational tone
- End with 5-8 highly relevant hashtags (mix of niche + broad)
- Do not use emojis excessively (2-3 max)
- Return ONLY the final caption text, no explanations`,
      },
      {
        role: "user",
        content: `Raw caption idea: "${rawCaption}"

Video transcription (what I say in the video):
"${transcription}"

Write the viral caption with hashtags:`,
      },
    ],
    max_tokens: 400,
  }),
});

const viralCaption = captionResp.choices[0].message.content.trim();

// ── Step 2: Build edit plan summary ───────────────────────────────────────
const planSummary = editPlan
  .map(
    (p, i) =>
      `• B-roll ${p.clipIndex + 1} at ${p.startTime}s for ${p.duration}s — ${p.reason}`
  )
  .join("\n");

// ── Step 3: Send video to Telegram ────────────────────────────────────────
// Send the video file
await this.helpers.httpRequest({
  method: "POST",
  url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendVideo`,
  body: {
    chat_id: chatId,
    video: finalVideoUrl,
    caption: viralCaption,
    parse_mode: "Markdown",
    supports_streaming: true,
  },
  json: true,
});

// ── Step 4: Send edit plan details as a follow-up message ─────────────────
await this.helpers.httpRequest({
  method: "POST",
  url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
  body: {
    chat_id: chatId,
    text: `✅ *Video ready!*\n\n*Edit Plan Used:*\n${planSummary}\n\n*Caption Generated:*\n${viralCaption}`,
    parse_mode: "Markdown",
  },
  json: true,
});

return [{
  json: {
    success: true,
    chatId,
    viralCaption,
    finalVideoUrl,
    editPlan,
  },
}];

// NODE: Error Handler
// Catches any pipeline error and sends a friendly message to the user

const TELEGRAM_BOT_TOKEN = "8754596174:AAHVBRlpbtevRd0Lo55dK1rlleIyXJ6bXfc";

// Try to extract chatId from the last known good data
const inputData = $input.first().json;
const chatId = inputData.chatId || null;

const errorMessage = $input.first().error?.message || "Unknown error";

if (chatId) {
  await this.helpers.httpRequest({
    method: "POST",
    url: `https://api.telegram.org/bot${TELEGRAM_BOT_TOKEN}/sendMessage`,
    body: {
      chat_id: chatId,
      text: `❌ Something went wrong during video generation.\n\nError: ${errorMessage}\n\nPlease try again by sending your voice note first.`,
    },
    json: true,
  });
}

return [{ json: { handled: true, error: errorMessage } }];
